let timer = setInterval(flashText, 5000);

console.log(timer);

function changeColor() {
  // check if an interval has already been set up
  if (!timer) {
    timer = setInterval(flashText, 5000);
  }
}

function changePhoto() {
  const oElem = document.getElementById(".");
}
